function ExerciseAnim({ title }) {
  const tLow = (title || "").toLowerCase();
  let img = POSE_MAP[tLow];
  if (!img) {
    // Fallback: find first key that appears in title
    const found = Object.keys(POSE_MAP).find(k => tLow.includes(k.split(" ")[0]) && tLow.includes(k.split(" ").slice(-1)[0]));
    img = found ? POSE_MAP[found] : POSE_SEATED_FORWARD;
  }
  return (
    <div style={{ width:"100%", marginBottom:8, borderRadius:12, overflow:"hidden",
      background:"#9aafac", border:"1px solid rgba(255,255,255,0.07)" }}>
      <img src={img} alt={title}
        style={{ width:"100%", display:"block", objectFit:"contain" }}/>
    </div>
  );
}


