function SectionTitle({ emoji, text, multi, lang }) {
  return (
    <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:12 }}>
      <span style={{ fontSize:20 }}>{emoji}</span>
      <div>
        <span style={{ color:"white", fontWeight:700, fontSize:15 }}>{text}</span>
        {multi && <span style={{ color:"rgba(255,255,255,0.4)", fontSize:12, marginLeft:6 }}>{lang==="fr"?"(plusieurs choix)":"(multiple choice)"}</span>}
      </div>
    </div>
  );
}

function OptBtn({ label, icon, active, onClick, fullWidth }) {
  return (
    <button onClick={onClick} style={{
      padding:"11px 10px", borderRadius:10,
      color: active ? "white" : "rgba(255,255,255,0.75)",
      fontSize:13, cursor:"pointer", textAlign:"center",
      width: fullWidth ? "100%" : undefined,
      background: active ? "rgba(13,207,198,0.18)" : "rgba(255,255,255,0.05)",
      border: active ? "1px solid #0dcfc6" : "1px solid rgba(255,255,255,0.1)",
      fontWeight: active ? 600 : 400,
      display:"flex", alignItems:"center", justifyContent:"center", gap:6,
    }}>
      {icon && <span>{icon}</span>}{label}
    </button>
  );
}

function OptBtnFull({ label, icon, active, onClick }) {
  return (
    <button onClick={onClick} style={{
      padding:"12px 14px", borderRadius:10, width:"100%",
      color: active ? "white" : "rgba(255,255,255,0.75)",
      fontSize:14, cursor:"pointer", textAlign:"left",
      background: active ? "rgba(13,207,198,0.18)" : "rgba(255,255,255,0.05)",
      border: active ? "1px solid #0dcfc6" : "1px solid rgba(255,255,255,0.1)",
      fontWeight: active ? 600 : 400, marginBottom:8,
      display:"flex", alignItems:"center", gap:8,
    }}>
      {icon && <span>{icon}</span>}{label}
    </button>
  );
}

